head.b:skin:
/*
Variable definitions
====================
<Variable name="bgColor" description="Background" type="color" default="#f2f2f7" value="#f2f2f7"/>
<Variable name="textColor" description="Text" type="color" default="#1c1c1e" value="#1c1c1e"/>
<Variable name="accentColor" description="Accent" type="color" default="#0A84FF" value="#0A84FF"/>
<Variable name="cardColor" description="Card" type="color" default="#ffffff" value="#ffffff"/>
*/

/* ════════════ iOS 26 LIQUID GLASS THEME — 2026 ════════════ */
:root{
  color-scheme:light dark;
  --ios-blue:#0A84FF;
  --ios-indigo:#5E5CE6;
  --ios-purple:#BF5AF2;
  --ios-pink:#FF375F;
  --ios-red:#FF453A;
  --ios-orange:#FF9F0A;
  --ios-yellow:#FFD60A;
  --ios-green:#30D158;
  --ios-mint:#66D4CF;
  --ios-cyan:#64D2FF;
  --accent:var(--ios-blue);
  --accent-2:var(--ios-cyan);

  /* Light */
  --bg:#f2f2f7;
  --bg-elev:#ffffff;
  --surface:rgba(255,255,255,0.72);
  --surface-strong:rgba(255,255,255,0.88);
  --glass-border:rgba(255,255,255,0.55);
  --hairline:rgba(60,60,67,0.18);
  --fg:#1c1c1e;
  --fg-2:#3a3a3c;
  --fg-muted:#6b6b70;
  --fg-faint:#8e8e93;
  --shadow-sm:0 1px 2px rgba(0,0,0,.04),0 1px 6px rgba(0,0,0,.04);
  --shadow-md:0 6px 24px rgba(20,30,80,.08),0 2px 8px rgba(20,30,80,.04);
  --shadow-lg:0 20px 60px rgba(20,30,80,.14),0 6px 20px rgba(20,30,80,.06);

  --f-body:'Cairo','Tajawal',-apple-system,BlinkMacSystemFont,'SF Pro Display','Segoe UI',system-ui,sans-serif;
  --f-heading:'Cairo','Tajawal',-apple-system,BlinkMacSystemFont,system-ui,sans-serif;
  --f-mono:'SF Mono','Fira Code',ui-monospace,Menlo,Consolas,monospace;

  --r-xs:8px;--r-sm:12px;--r-md:16px;--r-lg:22px;--r-xl:28px;--r-2xl:34px;--r-full:9999px;
  --blur:saturate(180%) blur(22px);
  --blur-strong:saturate(200%) blur(32px);
  --ease:cubic-bezier(.22,.61,.36,1);
  --spring:cubic-bezier(.34,1.56,.64,1);
  --t-fast:.18s var(--ease);
  --t:.28s var(--ease);
  --t-slow:.5s var(--ease);
}
html[data-theme="dark"]{
  color-scheme:dark;
  --bg:#000000;
  --bg-elev:#1c1c1e;
  --surface:rgba(28,28,30,0.72);
  --surface-strong:rgba(28,28,30,0.88);
  --glass-border:rgba(255,255,255,0.10);
  --hairline:rgba(255,255,255,0.10);
  --fg:#f5f5f7;
  --fg-2:#e5e5ea;
  --fg-muted:#aeaeb2;
  --fg-faint:#8e8e93;
  --shadow-sm:0 1px 2px rgba(0,0,0,.5),0 1px 6px rgba(0,0,0,.35);
  --shadow-md:0 6px 30px rgba(0,0,0,.55),0 2px 8px rgba(0,0,0,.35);
  --shadow-lg:0 20px 60px rgba(0,0,0,.7),0 6px 20px rgba(0,0,0,.45);
}
@media (prefers-color-scheme: dark){
  html[data-theme="auto"]{
    color-scheme:dark;
    --bg:#000000;--bg-elev:#1c1c1e;
    --surface:rgba(28,28,30,0.72);--surface-strong:rgba(28,28,30,0.88);
    --glass-border:rgba(255,255,255,0.10);--hairline:rgba(255,255,255,0.10);
    --fg:#f5f5f7;--fg-2:#e5e5ea;--fg-muted:#aeaeb2;--fg-faint:#8e8e93;
    --shadow-sm:0 1px 2px rgba(0,0,0,.5),0 1px 6px rgba(0,0,0,.35);
    --shadow-md:0 6px 30px rgba(0,0,0,.55),0 2px 8px rgba(0,0,0,.35);
    --shadow-lg:0 20px 60px rgba(0,0,0,.7),0 6px 20px rgba(0,0,0,.45);
  }
}

*,*::before,*::after{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent}
html{scroll-behavior:smooth;-webkit-text-size-adjust:100%}
html,body{overflow-x:hidden;max-width:100vw}
body{
  background:var(--bg);
  color:var(--fg);
  font-family:var(--f-body);
  font-feature-settings:'kern','liga','ss01';
  -webkit-font-smoothing:antialiased;
  -moz-osx-font-smoothing:grayscale;
  line-height:1.75;
  direction:rtl;
  min-width:320px;
  padding-bottom:calc(92px + env(safe-area-inset-bottom));
  background-image:
    radial-gradient(1200px 600px at 100% -10%, rgba(10,132,255,0.10), transparent 60%),
    radial-gradient(900px 500px at -10% 30%, rgba(100,210,255,0.08), transparent 60%),
    radial-gradient(700px 500px at 50% 110%, rgba(191,90,242,0.07), transparent 60%);
  background-attachment:fixed;
}
img{max-width:100%;height:auto;display:block}
a{color:var(--accent);text-decoration:none;transition:color var(--t-fast)}
a:hover{color:var(--ios-indigo)}
ul,ol{list-style:none;padding:0;margin:0}
button{cursor:pointer;border:none;background:none;font-family:inherit;color:inherit}
h1,h2,h3,h4,h5,h6{font-family:var(--f-heading);font-weight:800;color:var(--fg);line-height:1.25;letter-spacing:-0.01em}
::selection{background:rgba(10,132,255,0.25);color:var(--fg)}
::-webkit-scrollbar{width:10px;height:10px}
::-webkit-scrollbar-track{background:transparent}
::-webkit-scrollbar-thumb{background:rgba(127,127,127,.35);border-radius:10px;border:2px solid transparent;background-clip:padding-box}
::-webkit-scrollbar-thumb:hover{background:rgba(127,127,127,.55);background-clip:padding-box}

/* Reading progress */
.read-progress{position:fixed;top:0;left:0;right:0;height:3px;z-index:300;background:transparent;pointer-events:none}
.read-progress::after{content:'';display:block;height:100%;width:var(--rp,0%);background:linear-gradient(90deg,var(--ios-blue),var(--ios-cyan),var(--ios-purple));border-radius:0 4px 4px 0;transition:width .1s linear;box-shadow:0 0 18px rgba(10,132,255,.55)}

/* Header — Liquid Glass */
.ios-header,.v14-header,header[id*="header"],header[class*="header"],div[id*="header"],div[class*="header-wrap"]{
  position:sticky;top:0;z-index:100;padding:10px 12px 6px;
  background:transparent;
  border:0;
}
.dynamic-island,.v14-island{
  background:var(--surface-strong);
  -webkit-backdrop-filter:var(--blur);
  backdrop-filter:var(--blur);
  border:1px solid var(--glass-border);
  border-radius:var(--r-2xl);
  padding:10px 14px 10px 18px;
  display:flex;align-items:center;justify-content:space-between;gap:10px;
  max-width:980px;margin:0 auto;
  box-shadow:var(--shadow-md);
  position:relative;overflow:hidden;
}
.dynamic-island::before{content:'';position:absolute;inset:0;background:linear-gradient(135deg,rgba(255,255,255,.18),transparent 40%,rgba(255,255,255,.06));pointer-events:none;border-radius:inherit}
.brand a,.blog-title a,.header-title a,#header h1 a,h1.title a,.blog-name a,.title a,.v14-brand a,.v14-brand{
  font-family:var(--f-heading);
  font-weight:900;
  font-size:clamp(16px,3.6vw,20px);
  background:linear-gradient(135deg,var(--ios-blue) 0%,var(--ios-indigo) 50%,var(--ios-purple) 100%);
  -webkit-background-clip:text;background-clip:text;color:transparent;
  letter-spacing:-0.02em;
  text-decoration:none;
  display:inline-flex;align-items:center;gap:8px;
}
.brand a::before{content:'';width:10px;height:10px;border-radius:50%;background:linear-gradient(135deg,var(--ios-blue),var(--ios-cyan));box-shadow:0 0 14px var(--ios-blue);flex:none}
.header-actions{display:flex;gap:6px;align-items:center}
.icon-btn{
  background:rgba(120,120,128,0.14);
  border:1px solid var(--glass-border);
  border-radius:50%;width:38px;height:38px;
  display:inline-flex;align-items:center;justify-content:center;
  color:var(--fg);
  transition:transform var(--t-fast),background var(--t-fast),color var(--t-fast);
  -webkit-backdrop-filter:blur(10px);backdrop-filter:blur(10px);
}
.icon-btn:hover{background:var(--accent);color:#fff;transform:scale(1.06)}
.icon-btn:active{transform:scale(.94)}
.icon-btn svg{width:18px;height:18px;stroke-width:2.2}

/* Search */
.search-panel,.v14-search{
  display:none;max-width:980px;margin:8px auto 0;padding:0 12px;
}
.search-panel.open,.v14-search.open{display:block;animation:slideDown .28s var(--spring)}
.search-panel form{
  display:flex;gap:8px;
  background:var(--surface-strong);
  -webkit-backdrop-filter:var(--blur);backdrop-filter:var(--blur);
  border:1px solid var(--glass-border);
  border-radius:var(--r-lg);padding:8px;
  box-shadow:var(--shadow-md);
}
.search-panel input{flex:1;background:transparent;border:0;outline:none;color:var(--fg);font-family:inherit;padding:10px 14px;font-size:15px}
.search-panel input::placeholder{color:var(--fg-faint)}
.search-panel button{background:linear-gradient(135deg,var(--ios-blue),var(--ios-indigo));color:#fff;border:0;border-radius:var(--r-sm);padding:10px 22px;font-weight:700;letter-spacing:-.01em;transition:transform var(--t-fast)}
.search-panel button:hover{transform:scale(1.03)}
@keyframes slideDown{from{opacity:0;transform:translateY(-10px)}to{opacity:1;transform:none}}

/* Layout */
main{padding:18px 0 40px}
.container{max-width:1200px;margin:0 auto;padding:0 16px}
.layout{display:grid;grid-template-columns:minmax(0,1fr);gap:22px;max-width:1200px;margin:0 auto;padding:0 14px}
@media(min-width:980px){.layout{grid-template-columns:minmax(0,1fr) 320px;align-items:start}}
.main-col{min-width:0}
.sidebar-col{min-width:0;position:sticky;top:78px;align-self:start}

/* Section title chip */
.section-title{
  display:inline-flex;align-items:center;gap:8px;
  font-size:13px;font-weight:700;color:var(--fg-muted);
  background:var(--surface);
  -webkit-backdrop-filter:blur(14px);backdrop-filter:blur(14px);
  border:1px solid var(--glass-border);
  padding:6px 14px;border-radius:var(--r-full);
  margin-bottom:14px;
}
.section-title::before{content:'';width:6px;height:6px;border-radius:50%;background:linear-gradient(135deg,var(--ios-blue),var(--ios-cyan))}

/* Post cards grid */
#main .blog-posts,.posts-container{display:grid;grid-template-columns:1fr;gap:18px}
@media(min-width:640px){#main .blog-posts,.posts-container{grid-template-columns:repeat(2,1fr);gap:20px}}

.post-card,.v14-post-card,.post-outer,.blog-post,.post-item,.hentry{
  background:var(--surface);
  -webkit-backdrop-filter:var(--blur);backdrop-filter:var(--blur);
  border:1px solid var(--glass-border);
  border-radius:var(--r-xl);
  overflow:hidden;
  transition:transform var(--t),box-shadow var(--t),border-color var(--t);
  position:relative;
  box-shadow:var(--shadow-sm);
}
.post-card::after,.v14-post-card::after{
  content:'';position:absolute;inset:0;pointer-events:none;border-radius:inherit;
  background:linear-gradient(135deg,rgba(255,255,255,.10),transparent 35%,transparent 65%,rgba(255,255,255,.04));
  mix-blend-mode:overlay;opacity:.7;
}
.post-card:hover,.v14-post-card:hover,.post-outer:hover{
  transform:translateY(-6px);
  box-shadow:var(--shadow-lg);
  border-color:rgba(10,132,255,.35);
}
.post-thumb,.post-thumbnail,.post-image,.post-card-thumb{
  aspect-ratio:16/10;overflow:hidden;display:block;width:100%;
  background:linear-gradient(135deg,rgba(10,132,255,.12),rgba(191,90,242,.10));
  position:relative;
}
.post-thumb img,.post-thumbnail img,.post-image img,.post-card-thumb img,.post-outer img:first-of-type{
  width:100%;height:100%;object-fit:cover;border-radius:0;
  transition:transform .6s var(--ease);display:block;
}
.post-card:hover img,.v14-post-card:hover img,.post-outer:hover img{transform:scale(1.06)}
.post-body,.post-card-body,.post-item-content{padding:16px 18px 18px;position:relative;z-index:1}
.post-title,.post-card h2,.post-outer h2,h3.post-title,.entry-title{
  font-size:clamp(15.5px,2.6vw,18px);font-weight:800;color:var(--fg);
  line-height:1.4;margin-bottom:10px;letter-spacing:-0.012em;
}
.post-title a,.post-card h2 a,.post-outer h2 a{color:var(--fg);text-decoration:none}
.post-title a:hover,.post-card h2 a:hover{color:var(--accent)}
.post-meta,.post-card-meta,.date-header{
  font-size:12px;color:var(--fg-muted);margin-bottom:8px;
  display:flex;flex-wrap:wrap;gap:6px 12px;align-items:center;
}
.post-meta span{display:inline-flex;align-items:center;gap:4px}
.post-snippet,.post-card-excerpt,.item-snippet-text{
  font-size:13.5px;color:var(--fg-muted);line-height:1.7;
  display:-webkit-box;-webkit-line-clamp:3;-webkit-box-orient:vertical;overflow:hidden;
}

/* Single post */
.single-post,.v14-single-post,.post-body-container,.item-body,.post-page{
  background:var(--surface);
  -webkit-backdrop-filter:var(--blur);backdrop-filter:var(--blur);
  border:1px solid var(--glass-border);
  border-radius:var(--r-2xl);
  padding:clamp(20px,4vw,38px);
  box-shadow:var(--shadow-md);
  position:relative;
}
.single-post h1,.entry-title.post-title,h1.post-title{
  font-size:clamp(22px,4.5vw,34px);font-weight:900;margin-bottom:14px;color:var(--fg);letter-spacing:-0.02em;line-height:1.2;
}
.post-content,.post-body,.entry-content{
  font-size:clamp(15px,2vw,16.5px);line-height:1.95;color:var(--fg-2);
  word-wrap:break-word;overflow-wrap:break-word;
}
.post-content p{margin-bottom:1.1em}
.post-content h2,.post-content h3,.post-content h4{margin:1.6em 0 .6em;font-weight:800;color:var(--fg);letter-spacing:-0.015em}
.post-content a{color:var(--accent);text-decoration:underline;text-decoration-color:rgba(10,132,255,.35);text-underline-offset:3px}
.post-content a:hover{text-decoration-color:var(--accent)}
.post-content img,.post-content iframe{margin:1.4em auto;max-width:100%;height:auto;border-radius:var(--r-lg);box-shadow:var(--shadow-md)}
.post-content iframe{width:100%;aspect-ratio:16/9}
.post-content blockquote{
  border-right:3px solid var(--accent);
  padding:14px 20px;margin:1.4em 0;
  background:rgba(10,132,255,0.06);
  border-radius:0 var(--r-md) var(--r-md) 0;
  color:var(--fg);font-style:italic;
}
.post-content pre,.post-content code{font-family:var(--f-mono);background:rgba(120,120,128,.12);border-radius:6px;padding:2px 6px;font-size:.88em}
.post-content pre{padding:16px;overflow-x:auto;border-radius:var(--r-md);border:1px solid var(--hairline)}
.post-content table{width:100%;border-collapse:collapse;margin:1em 0;border-radius:var(--r-md);overflow:hidden}
.post-content th,.post-content td{border:1px solid var(--hairline);padding:10px 14px;text-align:right}
.post-content th{background:rgba(120,120,128,.10);font-weight:700;color:var(--fg)}
.post-footer,.post-labels-container{margin-top:24px;padding-top:18px;border-top:1px solid var(--hairline);display:flex;flex-wrap:wrap;gap:8px;align-items:center}
.post-labels a,.label-link,.post-footer a{
  background:rgba(120,120,128,.14);
  color:var(--fg-2);
  padding:6px 14px;border-radius:var(--r-full);
  font-size:12px;font-weight:600;
  border:1px solid var(--glass-border);
  transition:all var(--t-fast);
}
.post-labels a:hover,.post-footer a:hover{background:var(--accent);color:#fff;border-color:var(--accent);transform:translateY(-1px)}

/* Share actions */
.post-actions{display:flex;flex-wrap:wrap;gap:8px;margin-top:18px}
.post-actions button{background:rgba(120,120,128,.14);border:1px solid var(--glass-border);border-radius:var(--r-full);padding:8px 16px;font-size:13px;font-weight:600;color:var(--fg);display:inline-flex;gap:6px;align-items:center;transition:all var(--t-fast)}
.post-actions button:hover{background:var(--accent);color:#fff;border-color:var(--accent);transform:translateY(-1px)}
.post-actions svg{width:15px;height:15px}

/* Sidebar widgets */
.sidebar-col .widget,.sidebar .widget,#sidebar .widget{
  background:var(--surface);
  -webkit-backdrop-filter:var(--blur);backdrop-filter:var(--blur);
  border:1px solid var(--glass-border);
  border-radius:var(--r-xl);
  padding:16px 18px;margin-bottom:16px;
  overflow:hidden;
  box-shadow:var(--shadow-sm);
  position:relative;
}
.sidebar-col .widget::before{content:'';position:absolute;top:0;left:0;right:0;height:3px;background:linear-gradient(90deg,var(--ios-blue),var(--ios-cyan),var(--ios-purple));border-radius:var(--r-xl) var(--r-xl) 0 0;opacity:.8}
.widget .title,.widget-title,.widget h2,.widget h3,#sidebar .title{
  font-size:14px;font-weight:800;color:var(--fg);
  margin-bottom:14px;padding-bottom:10px;
  border-bottom:1px solid var(--hairline);
  display:flex;align-items:center;gap:8px;letter-spacing:-0.01em;
}
.widget .title::before,.widget-title::before{content:'';width:4px;height:16px;border-radius:2px;background:linear-gradient(180deg,var(--ios-blue),var(--ios-cyan))}
.widget ul li{padding:8px 0;border-bottom:1px solid var(--hairline);transition:padding var(--t-fast)}
.widget ul li:last-child{border:0}
.widget ul li:hover{padding-right:6px}
.widget ul li a,.widget a{color:var(--fg-2);font-size:13.5px;font-weight:500;transition:color var(--t-fast)}
.widget ul li a:hover,.widget a:hover{color:var(--accent)}
.widget img{max-width:64px;height:auto;border-radius:var(--r-sm);display:inline;vertical-align:middle}
.widget .widget-content img{max-width:100%}
.widget iframe{max-width:100%;border-radius:var(--r-md)}

/* Popular posts custom */
.popular-posts li{padding:10px 0;border-bottom:1px solid var(--hairline);counter-increment:pp}
.popular-posts li:last-child{border:0}
.pp-link{display:flex;gap:12px;align-items:center;color:var(--fg);position:relative}
.pp-link::after{content:counter(pp,decimal);position:absolute;top:-4px;right:-4px;font-size:11px;font-weight:800;color:var(--accent);background:rgba(10,132,255,.10);border:1px solid var(--glass-border);border-radius:50%;width:22px;height:22px;display:flex;align-items:center;justify-content:center}
.pp-thumb{width:60px;height:60px;border-radius:var(--r-md);object-fit:cover;flex:none;background:linear-gradient(135deg,rgba(10,132,255,.15),rgba(191,90,242,.15));display:flex;align-items:center;justify-content:center;font-size:22px;border:1px solid var(--glass-border)}
.pp-meta{display:flex;flex-direction:column;gap:2px;min-width:0;flex:1;padding-left:18px}
.pp-title{font-size:13px;font-weight:700;color:var(--fg);line-height:1.4;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden}
.pp-snippet{font-size:11.5px;color:var(--fg-faint);display:-webkit-box;-webkit-line-clamp:1;-webkit-box-orient:vertical;overflow:hidden}
.popular-posts{counter-reset:pp}

/* Labels cloud */
.PageList ul,.LinkList ul,.label-size,.cloud-label-widget-content{display:flex;flex-wrap:wrap;gap:8px}
.PageList li,.LinkList li{padding:0;border:0!important}
.PageList a,.LinkList a,.label-name,.label-size a{
  background:rgba(120,120,128,.14);
  border:1px solid var(--glass-border);
  padding:6px 13px;border-radius:var(--r-full);
  display:inline-block;
  color:var(--fg-2)!important;font-size:12.5px;font-weight:600;
  transition:all var(--t-fast);
}
.PageList a:hover,.LinkList a:hover,.label-name:hover,.label-size a:hover{
  background:linear-gradient(135deg,var(--ios-blue),var(--ios-indigo));
  border-color:var(--ios-blue);color:#fff!important;transform:translateY(-1px) scale(1.03);
}
.label-size-1 a{font-size:11px}.label-size-2 a{font-size:12px}.label-size-3 a{font-size:13px}.label-size-4 a{font-size:14px}.label-size-5 a{font-size:15px;font-weight:700}

/* Drawer */
.drawer,.v14-drawer{position:fixed;inset:0;background:rgba(0,0,0,.45);-webkit-backdrop-filter:blur(8px);backdrop-filter:blur(8px);z-index:200;display:none;animation:fadeIn .25s var(--ease)}
.drawer.open,.v14-drawer.open{display:block}
@keyframes fadeIn{from{opacity:0}to{opacity:1}}
.drawer-inner,.v14-drawer-inner{
  position:fixed;top:0;right:0;bottom:0;width:min(320px,84vw);
  background:var(--surface-strong);
  -webkit-backdrop-filter:var(--blur-strong);backdrop-filter:var(--blur-strong);
  border-left:1px solid var(--glass-border);
  padding:24px 18px;overflow-y:auto;
  transform:translateX(100%);transition:transform .32s var(--spring);
  box-shadow:-20px 0 60px rgba(0,0,0,.3);
}
.drawer.open .drawer-inner,.v14-drawer.open .v14-drawer-inner{transform:translateX(0)}
.drawer-close{position:absolute;top:14px;left:14px}
.drawer h3{font-size:20px;font-weight:800;color:var(--fg);margin-bottom:18px;letter-spacing:-0.02em}
.drawer .widget{background:transparent;border:0;padding:6px 0;margin-bottom:10px;box-shadow:none}
.drawer .widget::before{display:none}
.drawer .widget .title{font-size:12px;color:var(--fg-faint);text-transform:uppercase;letter-spacing:.08em;border:0;padding:0;margin-bottom:10px}
.drawer .widget .title::before{display:none}
.drawer .widget ul{display:flex;flex-direction:column;gap:2px}
.drawer .widget ul li{padding:0;border:0}
.drawer .widget ul li a,.drawer .widget a{
  display:block;color:var(--fg)!important;font-size:15px;font-weight:600;
  padding:12px 14px;border-radius:var(--r-md);
  background:rgba(120,120,128,.10);
  transition:all var(--t-fast);
}
.drawer .widget ul li a:hover,.drawer .widget a:hover{background:var(--accent);color:#fff!important;transform:translateX(-4px)}

/* Tab bar — iOS 26 Dock */
.tab-bar,.v14-tabbar{
  position:fixed;
  bottom:calc(14px + env(safe-area-inset-bottom));
  left:50%;transform:translateX(-50%);
  background:var(--surface-strong);
  -webkit-backdrop-filter:var(--blur-strong);backdrop-filter:var(--blur-strong);
  border:1px solid var(--glass-border);
  border-radius:var(--r-full);
  padding:8px 10px;
  display:flex;gap:4px;z-index:100;
  box-shadow:var(--shadow-lg);
  max-width:calc(100vw - 28px);
}
.tab-bar a,.tab-bar button{
  display:flex;flex-direction:column;align-items:center;justify-content:center;
  padding:8px 14px;border-radius:var(--r-full);min-width:60px;
  font-size:10.5px;font-weight:600;color:var(--fg-muted);
  background:none;border:0;cursor:pointer;font-family:inherit;
  transition:all var(--t-fast);
}
.tab-bar a:hover,.tab-bar a.active,.tab-bar button:hover{
  background:linear-gradient(135deg,rgba(10,132,255,.15),rgba(100,210,255,.12));
  color:var(--accent);
}
.tab-bar a.active{color:var(--accent)}
.tab-bar svg{width:22px;height:22px;margin-bottom:3px;stroke:currentColor;fill:none;stroke-width:2}

/* Footer */
footer.site-footer,.v14-footer,.site-footer,.footer,.blog-footer{
  background:transparent;
  border-top:1px solid var(--hairline);
  text-align:center;
  padding:32px 16px calc(110px + env(safe-area-inset-bottom));
  color:var(--fg-muted);font-size:13px;margin-top:30px;
}
.footer a,.site-footer a{color:var(--accent)}
.site-footer .footer-brand{font-weight:800;font-size:15px;background:linear-gradient(135deg,var(--ios-blue),var(--ios-purple));-webkit-background-clip:text;background-clip:text;color:transparent;display:inline-block;margin-bottom:6px;letter-spacing:-0.01em}

/* Pager */
.blog-pager,.pager{text-align:center;margin:30px 0;display:flex;justify-content:space-between;gap:12px;flex-wrap:wrap}
.blog-pager a,.pager a{
  background:var(--surface);
  -webkit-backdrop-filter:var(--blur);backdrop-filter:var(--blur);
  border:1px solid var(--glass-border);
  padding:11px 22px;border-radius:var(--r-full);
  color:var(--fg);font-weight:700;font-size:14px;
  transition:all var(--t);
  box-shadow:var(--shadow-sm);
}
.blog-pager a:hover,.pager a:hover{
  background:linear-gradient(135deg,var(--ios-blue),var(--ios-indigo));
  border-color:var(--ios-blue);color:#fff;transform:translateY(-2px);
  box-shadow:var(--shadow-md);
}

/* Comments */
.comments,.comment-thread{
  background:var(--surface);
  -webkit-backdrop-filter:var(--blur);backdrop-filter:var(--blur);
  border:1px solid var(--glass-border);
  border-radius:var(--r-2xl);
  padding:22px;margin-top:22px;
  box-shadow:var(--shadow-sm);
}
.comments iframe{width:100%;border:0;border-radius:var(--r-md)}

/* Attribution */
.Attribution,.widget.Attribution{background:transparent!important;border:0!important;padding:4px 0!important;color:var(--fg-faint)!important;font-size:12px;box-shadow:none!important}
.Attribution::before{display:none}

/* Back to top */
#back-to-top{
  position:fixed;
  bottom:calc(95px + env(safe-area-inset-bottom));
  left:18px;z-index:90;
  background:var(--surface-strong);
  -webkit-backdrop-filter:var(--blur);backdrop-filter:var(--blur);
  color:var(--accent);
  border:1px solid var(--glass-border);
  border-radius:50%;
  width:46px;height:46px;
  display:flex;align-items:center;justify-content:center;
  font-size:18px;font-weight:800;cursor:pointer;
  box-shadow:var(--shadow-md);
  opacity:0;pointer-events:none;transform:translateY(10px) scale(.85);
  transition:all var(--t) var(--spring);
}
#back-to-top.visible{opacity:1;pointer-events:auto;transform:none}
#back-to-top:hover{background:var(--accent);color:#fff;transform:scale(1.08)}
#back-to-top svg{width:20px;height:20px;stroke:currentColor;fill:none;stroke-width:2.4}

/* Social icons in widgets (kept) */
.v123-social{display:flex;flex-wrap:wrap;gap:8px;margin-top:6px}
.v123-soc{width:38px;height:38px;border-radius:var(--r-md);display:inline-flex;align-items:center;justify-content:center;color:#fff;transition:transform var(--t-fast),box-shadow var(--t-fast)}
.v123-soc:hover{transform:translateY(-2px) scale(1.05);box-shadow:0 8px 20px rgba(0,0,0,.25)}
.v123-soc svg{width:18px;height:18px;fill:currentColor}

/* Animations - staggered entrance */
@keyframes riseIn{from{opacity:0;transform:translateY(18px)}to{opacity:1;transform:none}}
.post-card,.v14-post-card,.sidebar-col .widget,.single-post,.v14-single-post{animation:riseIn .55s var(--ease) both}
#main .blog-posts .post-card:nth-child(1){animation-delay:.04s}
#main .blog-posts .post-card:nth-child(2){animation-delay:.08s}
#main .blog-posts .post-card:nth-child(3){animation-delay:.12s}
#main .blog-posts .post-card:nth-child(4){animation-delay:.16s}
#main .blog-posts .post-card:nth-child(5){animation-delay:.2s}
#main .blog-posts .post-card:nth-child(6){animation-delay:.24s}
.sidebar-col .widget:nth-child(1){animation-delay:.18s}
.sidebar-col .widget:nth-child(2){animation-delay:.24s}
.sidebar-col .widget:nth-child(3){animation-delay:.30s}
.sidebar-col .widget:nth-child(4){animation-delay:.36s}

@media (prefers-reduced-motion: reduce){
  *,*::before,*::after{animation:none!important;transition:none!important}
}

/* Responsive */
@media(max-width:640px){
  .single-post,.v14-single-post,.item-body{padding:18px!important}
  h1.post-title,.entry-title{font-size:22px!important}
  .ios-header,.v14-header{padding:8px 10px 4px!important}
  .dynamic-island,.v14-island{padding:9px 12px;border-radius:24px}
  .icon-btn{width:36px;height:36px}
  .widget img{max-width:46px}
  .layout{padding:0 10px;gap:14px}
  .tab-bar,.v14-tabbar{padding:6px 8px;gap:2px;bottom:10px}
  .tab-bar a,.tab-bar button{padding:7px 11px;font-size:9.5px;min-width:54px}
  .post-body,.post-card-body{padding:14px}
  .post-title{font-size:15px!important}
  .sidebar-col{position:static}
  #back-to-top{bottom:85px;left:12px;width:42px;height:42px}
}
@media(min-width:601px) and (max-width:979px){
  .layout{grid-template-columns:minmax(0,1fr)}
  .sidebar-col{order:2;position:static}
}
@media(min-width:1200px){
  .layout{max-width:1200px;margin:0 auto}
  .container{max-width:1200px}
  body{padding-bottom:20px}
  .tab-bar,.v14-tabbar{display:none}
  #back-to-top{bottom:30px}
}

body.script:
/**/
/* iOS 26 Theme Engine — 2026 */
(function(){
  'use strict';
  var doc=document,html=doc.documentElement,LS='ios26-theme';

  /* Theme: light / dark / auto */
  function applyTheme(t){html.setAttribute('data-theme',t||'auto');try{localStorage.setItem(LS,t);}catch(e){}updateMeta(t);}
  function updateMeta(t){var m=doc.querySelector('meta[name="theme-color"]');if(!m)return;var dark=t==='dark'||(t==='auto'&&matchMedia('(prefers-color-scheme:dark)').matches);m.setAttribute('content',dark?'#000000':'#f2f2f7');}
  window.toggleTheme=function(){var cur=html.getAttribute('data-theme')||'auto';var isDark=cur==='dark'||(cur==='auto'&&matchMedia('(prefers-color-scheme:dark)').matches);applyTheme(isDark?'light':'dark');};
  try{var saved=localStorage.getItem(LS);if(saved)applyTheme(saved);else updateMeta('auto');}catch(e){}
  matchMedia('(prefers-color-scheme:dark)').addEventListener('change',function(){var cur=html.getAttribute('data-theme');if(cur==='auto')updateMeta('auto');});

  /* Class aliases for compatibility */
  function applyAliases(){
    var map={'ios-header':'v14-header','dynamic-island':'v14-island','brand':'v14-brand','search-panel':'v14-search','drawer':'v14-drawer','drawer-inner':'v14-drawer-inner','tab-bar':'v14-tabbar','site-footer':'v14-footer','post-card':'v14-post-card','single-post':'v14-single-post'};
    Object.keys(map).forEach(function(src){doc.querySelectorAll('.'+src).forEach(function(el){el.classList.add(map[src]);});});
    var h1=doc.querySelector('#header h1,#header .title,h1.title,.blog-title');
    if(h1)h1.classList.add('v14-brand');
  }

  /* Back-to-top */
  function initBackToTop(){
    var btn=doc.getElementById('back-to-top');
    if(!btn){btn=doc.createElement('button');btn.id='back-to-top';btn.setAttribute('aria-label','للأعلى');btn.innerHTML='<svg viewBox="0 0 24 24" stroke-linecap="round" stroke-linejoin="round"><path d="m18 15-6-6-6 6"/></svg>';doc.body.appendChild(btn);}
    window.addEventListener('scroll',function(){btn.classList.toggle('visible',window.scrollY>320);},{passive:true});
    btn.addEventListener('click',function(){window.scrollTo({top:0,behavior:'smooth'});});
  }

  /* Reading progress bar */
  function initReadProgress(){
    var bar=doc.getElementById('readProgress');
    if(!bar)return;
    function update(){
      var h=doc.documentElement,b=doc.body;
      var st=h.scrollTop||b.scrollTop;
      var sh=(h.scrollHeight||b.scrollHeight)-h.clientHeight;
      var pct=sh>0?Math.min(100,Math.max(0,(st/sh)*100)):0;
      bar.style.setProperty('--rp',pct+'%');
    }
    window.addEventListener('scroll',update,{passive:true});
    window.addEventListener('resize',update,{passive:true});
    update();
  }

  /* Share / drawer / search helpers */
  window.openSearch=function(){var p=doc.getElementById('searchPanel');if(p){p.classList.add('open');var i=p.querySelector('input');if(i)i.focus();}closeDrawer();};
  window.closeSearch=function(){var p=doc.getElementById('searchPanel');if(p)p.classList.remove('open');};
  window.openDrawer=function(){var d=doc.getElementById('sideDrawer')||doc.querySelector('.drawer');if(d){d.classList.add('open');doc.body.style.overflow='hidden';}closeSearch();};
  window.closeDrawer=function(){var d=doc.getElementById('sideDrawer')||doc.querySelector('.drawer');if(d){d.classList.remove('open');doc.body.style.overflow='';}};

  /* Web Share API for posts */
  window.iosShare=function(url,title){
    if(navigator.share){navigator.share({title:title||doc.title,url:url||location.href}).catch(function(){});}
    else if(navigator.clipboard){navigator.clipboard.writeText(url||location.href).then(function(){alert('تم نسخ الرابط');});}
  };

  /* Inject share bar on single post */
  function initShareBar(){
    var sp=doc.querySelector('.single-post,.v14-single-post,.post-page');
    if(!sp||sp.querySelector('.post-actions'))return;
    var bar=doc.createElement('div');bar.className='post-actions';
    bar.innerHTML='<button onclick="iosShare()" type="button"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M4 12v8a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2v-8"/><polyline points="16 6 12 2 8 6"/><line x1="12" x2="12" y1="2" y2="15"/></svg><span>مشاركة</span></button>'+
                  '<button onclick="window.print()" type="button"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="6 9 6 2 18 2 18 9"/><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"/><rect width="12" height="8" x="6" y="14"/></svg><span>طباعة</span></button>'+
                  '<button onclick="window.scrollTo({top:0,behavior:\'smooth\'})" type="button"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="m18 15-6-6-6 6"/></svg><span>أعلى</span></button>';
    sp.appendChild(bar);
  }

  /* Upgrade Blogger images quality */
  function upgradeImages(){
    doc.querySelectorAll('img').forEach(function(img){
      var s=img.getAttribute('src')||'';
      if(!s||!/blogger\.googleusercontent\.com|bp\.blogspot\.com/.test(s))return;
      var nu=s.replace(/\/(s|w)\d+(-h\d+)?(-c)?\//,'/w720-h420-c/').replace(/=s\d+(-c)?($|\?)/,'=w720-h420-c$2');
      if(nu!==s)img.setAttribute('src',nu);
    });
  }

  /* Lazy-load images */
  function lazyImages(){
    doc.querySelectorAll('img').forEach(function(img){
      if(!img.getAttribute('loading'))img.setAttribute('loading','lazy');
      if(!img.getAttribute('decoding'))img.setAttribute('decoding','async');
    });
  }

  /* Close drawer/search on outside click */
  doc.addEventListener('keydown',function(e){if(e.key==='Escape'){closeSearch();closeDrawer();}});
  doc.addEventListener('click',function(e){
    var d=doc.getElementById('sideDrawer')||doc.querySelector('.drawer');
    var di=doc.querySelector('.drawer-inner');
    if(d&&d.classList.contains('open')&&di&&!di.contains(e.target)){
      var isMenuBtn=!!e.target.closest('[onclick*="sideDrawer"],[aria-label="القائمة"],[aria-label="Menu"]');
      if(!isMenuBtn)closeDrawer();
    }
    var p=doc.getElementById('searchPanel');
    if(p&&p.classList.contains('open')&&!p.contains(e.target)){
      var isSearchBtn=!!e.target.closest('[onclick*="searchPanel"],[aria-label="بحث"],[aria-label="Search"]');
      if(!isSearchBtn)closeSearch();
    }
  });

  function init(){
    applyAliases();
    initBackToTop();
    initReadProgress();
    initShareBar();
    lazyImages();
    upgradeImages();
    var y=doc.getElementById('currentYear');if(y)y.textContent=new Date().getFullYear();
  }
  if(doc.readyState==='loading')doc.addEventListener('DOMContentLoaded',init);
  else init();
  window.addEventListener('load',upgradeImages);
})();
/**/
